class sle {
  async getInfo() {
    return (await Li.get("/users/info")).data;
  }

  async updateOnline() {
    return (await Li.post("/users/online")).data;
  }
}

const l$ = new sle;

let miningActive = false;
let checkedWallets = 0;

const hg = {
  getCheckedWalletsCount() {
    return {
      checkedWallets,
      newWallet: null
    };
  },

  getMiningStatus() {
    return {
      isActive: miningActive
    };
  },

  startMining() {
    miningActive = true;
    return { success: true };
  },

  stopMining() {
    miningActive = false;
    return { success: true };
  }
};

